import java.util.*;class ZeroSumSubarrays{public static void main(String[]a){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] arr=new int[n];for(int i=0;i<n;i++)arr[i]=s.nextInt();Map<Integer,Integer>m=new HashMap<>();int sum=0,count=0;m.put(0,1);for(int i=0;i<n;i++){sum+=arr[i];if(m.containsKey(sum))count+=m.get(sum);m.put(sum,m.getOrDefault(sum,0)+1);}System.out.println(count);}}